  {
    "name": "International Social Survey Programme (ISSP)",
    "description": "Cross-national annual modules on themes such as Religion, Social Inequality, Role of Government, Family and Changing Gender Roles, and social behaviour and attitudes.",
    "datasetUrl": "https://www.gesis.org/en/issp"
  },
  {
    "name": "European Values Study (EVS)",
    "description": "Long-term multinational study of values and beliefs across Europe, including religion and values, social and political attitudes, family and marriage, and views on government and the economy.",
    "datasetUrl": "https://www.gesis.org/en/evs"
  },
  {
    "name": "German Longitudinal Election Study (GLES)",
    "description": "Comprehensive study of electoral and political behaviour in Germany, including political attitudes, participation, party preferences, and evaluations of government and political systems.",
